// SPDX-License-Identifier: MIT
pragma solidity ^0.8.0;

// ══════════════════════════════════════════════════════════════
// REAL EXPLOIT PATTERNS — مأخوذة من هجمات حقيقية دفعت ملايين
// ══════════════════════════════════════════════════════════════

interface IERC20 {
    function transfer(address to, uint256 amount) external returns (bool);
    function transferFrom(address from, address to, uint256 amount) external returns (bool);
    function balanceOf(address account) external view returns (uint256);
    function approve(address spender, uint256 amount) external returns (bool);
    function totalSupply() external view returns (uint256);
}

interface IUniswapV2Pair {
    function getReserves() external view returns (uint112, uint112, uint32);
    function swap(uint256, uint256, address, bytes calldata) external;
}

interface ILendingPool {
    function flashLoan(address, address[] calldata, uint256[] calldata, uint256[] calldata, address, bytes calldata, uint16) external;
}

// ═══════════════════════════════════════════
// Pattern 1: Cream Finance style — Reentrancy + Oracle
// (Lost $130M in October 2021)
// ═══════════════════════════════════════════
contract VulnerableLending {
    mapping(address => uint256) public collateral;
    mapping(address => uint256) public debt;
    mapping(address => uint256) public balances;

    IERC20 public token;
    IUniswapV2Pair public pricePair;

    uint256 public totalDeposits;
    uint256 public totalBorrowed;

    constructor(address _token, address _pair) {
        token = IERC20(_token);
        pricePair = IUniswapV2Pair(_pair);
    }

    // VULN: Spot price oracle — flash loan manipulable
    function getCollateralValue(address user) public view returns (uint256) {
        (uint112 reserve0, uint112 reserve1,) = pricePair.getReserves();
        uint256 price = (uint256(reserve0) * 1e18) / uint256(reserve1);
        return collateral[user] * price / 1e18;
    }

    function deposit(uint256 amount) external {
        token.transferFrom(msg.sender, address(this), amount);
        collateral[msg.sender] += amount;
        totalDeposits += amount;
    }

    // VULN: Reentrancy — external call before state update
    function borrow(uint256 amount) external {
        uint256 collateralVal = getCollateralValue(msg.sender);
        require(collateralVal >= (debt[msg.sender] + amount) * 2, "Undercollateralized");

        // External call BEFORE state update
        (bool ok,) = msg.sender.call{value: amount}("");
        require(ok);

        debt[msg.sender] += amount;
        totalBorrowed += amount;
    }

    // VULN: Unchecked ERC20 return
    function withdraw(uint256 amount) external {
        require(collateral[msg.sender] >= amount);
        require(debt[msg.sender] == 0, "Has debt");
        collateral[msg.sender] -= amount;
        totalDeposits -= amount;
        token.transfer(msg.sender, amount);  // return not checked!
    }
}

// ═══════════════════════════════════════════
// Pattern 2: ERC4626 Vault — First depositor
// (Common in many protocols, found by auditors)
// ═══════════════════════════════════════════
contract VulnerableVault {
    IERC20 public asset;

    mapping(address => uint256) public shares;
    uint256 public totalShares;

    constructor(address _asset) {
        asset = IERC20(_asset);
    }

    function totalAssets() public view returns (uint256) {
        return asset.balanceOf(address(this));
    }

    // VULN: First depositor gets shares = amount, then donates to inflate
    function deposit(uint256 amount) external returns (uint256 sharesOut) {
        if (totalShares == 0) {
            sharesOut = amount;
        } else {
            sharesOut = (amount * totalShares) / totalAssets();
        }

        shares[msg.sender] += sharesOut;
        totalShares += sharesOut;
        asset.transferFrom(msg.sender, address(this), amount);
    }

    // VULN: Divide before multiply in redemption
    function redeem(uint256 shareAmount) external returns (uint256 assetsOut) {
        require(shares[msg.sender] >= shareAmount);

        assetsOut = (shareAmount / totalShares) * totalAssets();  // precision loss!

        shares[msg.sender] -= shareAmount;
        totalShares -= shareAmount;
        asset.transfer(msg.sender, assetsOut);  // unchecked return
    }
}

// ═══════════════════════════════════════════
// Pattern 3: Governance — tx.origin + no timelock
// ═══════════════════════════════════════════
contract VulnerableGovernance {
    address public owner;
    address public pendingOwner;
    mapping(address => bool) public admins;

    IERC20 public treasury;
    uint256 public totalFunds;

    constructor(address _treasury) {
        owner = msg.sender;
        treasury = IERC20(_treasury);
    }

    // VULN: tx.origin auth — phishable  
    function setAdmin(address admin, bool status) external {
        require(tx.origin == owner, "Not owner");
        admins[admin] = status;
    }

    // VULN: No timelock on critical operation
    function drainTreasury(address to) external {
        require(admins[msg.sender], "Not admin");
        uint256 bal = treasury.balanceOf(address(this));
        treasury.transfer(to, bal);  // unchecked
    }

    // VULN: Arbitrary external call
    function execute(address target, bytes calldata data) external {
        require(msg.sender == owner);
        (bool ok,) = target.call(data);
        // return not checked — silent failure
    }

    // VULN: Delegatecall to user-controlled address
    function upgradeAndCall(address impl, bytes calldata data) external {
        require(msg.sender == owner);
        (bool ok,) = impl.delegatecall(data);
    }
}

// ═══════════════════════════════════════════
// Pattern 4: DEX Router — Slippage + MEV
// ═══════════════════════════════════════════
contract VulnerableRouter {

    // VULN: No slippage protection — sandwich attackable
    function swap(address pair, uint256 amountIn, address tokenIn, address tokenOut) external {
        IERC20(tokenIn).transferFrom(msg.sender, pair, amountIn);

        (uint112 r0, uint112 r1,) = IUniswapV2Pair(pair).getReserves();

        // VULN: Uses spot reserves — manipulable
        uint256 amountOut = (amountIn * uint256(r1)) / (uint256(r0) + amountIn);

        IUniswapV2Pair(pair).swap(0, amountOut, msg.sender, "");
    }

    // VULN: Block.timestamp dependency for randomness
    function lottery(uint256 amount) external {
        require(amount > 0);
        bool winner = uint256(keccak256(abi.encodePacked(block.timestamp, msg.sender))) % 2 == 0;
        if (winner) {
            payable(msg.sender).transfer(amount * 2);
        }
    }
}

